<b>Workflow:</b> {{ $json.workflowName }}
<b>Failed Node:</b> {{ $json.failedNode }}
<b>Category:</b> {{ $json.categoryLabel }}
<b>Error:</b> <code>{{ $json.telegramSafeError }}</code>
<b>Execution:</b> "{{
<b>Trace:</b> <code>{{ $json.traceId }}</code>
