const circuitData = $input.first().json || {};

const errorData = (() => {
  try { return $('Enrich & Classify').first().json; }
  catch(e) {
    try { return $('Is Debounced?').first().json; }
    catch(e2) { return {}; }
  }
})();

const isDbError = !!(circuitData.error && typeof circuitData.error === 'object' && circuitData.error.message) || !circuitData.status;
const status = isDbError ? 'unknown' : String(circuitData.status || 'unknown');
const previousStatus = isDbError ? 'unknown' : String(circuitData.previous_status || status);
const errorCount = isDbError ? 0 : (parseInt(circuitData.error_count, 10) || 0);
const isTransition = !isDbError && !!circuitData.previous_status && status !== previousStatus;
const isCircuitOpen = status === 'open';
const isNewlyOpen = isTransition && status === 'open';
const isCircuitSuppressing = isCircuitOpen && !isNewlyOpen;

if (isCircuitSuppressing) {
  return [];
}

return [{
  json: {
    ...errorData,
    circuit_status: status,
    previous_status: previousStatus,
    error_count: errorCount,
    is_transition: isTransition,
    transition_logged: !!circuitData.transition_logged,
    is_circuit_open: isCircuitOpen,
    is_newly_open: isNewlyOpen,
    is_circuit_suppressing: false,
    is_db_error: isDbError,
    db_error_message: circuitData.error?.message || ''
  }
}];

const item = $input.first().json;

function htmlEscape(text) {
  return String(text || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

function clampTelegramHtml(value, max) {
  max = max || 3900;
  var s = String(value || '');
  if (s.length <= max) return s;
  var note = '\n\n\u26A0\uFE0F <i>Message truncated (exceeded Telegram limit)</i>';
  return s.substring(0, max - note.length) + note;
}

function formatTimestamp() {
  return new Date().toLocaleString('en-PH', {
    timeZone: 'Asia/Manila',
    year: 'numeric', month: 'short', day: 'numeric',
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    hour12: false
  });
}

var adviceMap = {
  auth: { cause: 'Credential expired, revoked, or permission issue.', action: 'Check credential validity and recent permission changes.' },
  rate_limit: { cause: 'External API quota or burst threshold reached.', action: 'Confirm provider rate limits; reduce concurrency or increase backoff.' },
  timeout: { cause: 'Slow dependency or long-running operation.', action: 'Check external service latency and node timeout settings.' },
  connectivity: { cause: 'Network, DNS, or remote service availability issue.', action: 'Check service status and recent infrastructure changes.' },
  code_bug: { cause: 'Expression or Code node received unexpected data shape.', action: 'Inspect input payload and add null guards.' },
  resource: { cause: 'Memory, heap, or platform resource pressure.', action: 'Check execution size, binary data, and container limits.' },
  unknown: { cause: 'Unclassified failure.', action: 'Open execution and inspect node output.' }
};

var advice = adviceMap[item.category] || adviceMap.unknown;

var circuitBanner = '';
if (item.is_newly_open) {
  circuitBanner = '\u{1F534} <b>CIRCUIT BREAKER OPENED</b>\n'
    + '<b>Threshold:</b> ' + item.error_count + ' of 5\n'
    + '<b>Effect:</b> New errors will be suppressed until recovery probe.\n\n';
}

var taxonomyLabel = 'NEW ERROR';
if (item.is_newly_open) taxonomyLabel = 'CIRCUIT OPEN';
else if (item.burstSuppressedCount > 0) taxonomyLabel = 'BURST UPDATE (+' + item.burstSuppressedCount + ' suppressed)';
else if (item.retryOf) taxonomyLabel = 'RETRY FAILED';

var circuitLine = item.is_db_error
  ? 'Circuit: \u26A0\uFE0F unknown \u2014 Postgres unavailable'
  : 'Circuit: Error ' + item.error_count + ' of 5';

var burstLine = item.burstSuppressedCount > 0
  ? '\n\u26A1 <b>Suppressed:</b> ' + item.burstSuppressedCount + ' duplicate(s) since last alert'
  : '';

var retryLine = item.retryable
  ? '<b>Retryable:</b> yes \u2014 auto-retry eligible'
  : item.retryOf
    ? '<b>Retryable:</b> no \u2014 this is already a retry execution'
    : '<b>Retryable:</b> no (' + item.categoryLabel + ')';

var executionLink = item.executionUrl
  ? '"''
  : 'unavailable';

var text;

if (item.severity === 'critical') {
  text = circuitBanner + item.severityIcon + ' <b>' + taxonomyLabel + ' \u2014 ' + htmlEscape(item.categoryLabel) + '</b>\n\n'
    + '<b>Workflow:</b> ' + htmlEscape(item.workflowName) + '\n'
    + '<b>Failed Node:</b> ' + htmlEscape(item.failedNode) + '\n'
    + '<b>Category:</b> ' + item.categoryLabel + '\n'
    + '<b>Error:</b> <code>' + item.htmlError + '</code>\n'
    + '<b>Execution:</b> ' + executionLink + '\n\n'
    + '\u{1F4A1} <b>Likely cause:</b> ' + advice.cause + '\n'
    + '\u{1F527} <b>Action:</b> ' + advice.action + '\n\n'
    + retryLine + '\n'
    + '<b>' + circuitLine + '</b>' + burstLine + '\n\n'
    + '<b>Trace:</b> <code>' + item.traceId + '</code>\n'
    + '<b>Timestamp:</b> ' + formatTimestamp();
} else {
  text = circuitBanner + item.severityIcon + ' <b>' + taxonomyLabel + ' \u2014 ' + htmlEscape(item.categoryLabel) + '</b>\n\n'
    + '<b>Workflow:</b> ' + htmlEscape(item.workflowName) + ' \u2192 ' + htmlEscape(item.failedNode) + '\n'
    + '<b>Error:</b> <code>' + item.htmlError + '</code>\n'
    + '<b>Execution:</b> ' + executionLink + '\n\n'
    + '\u{1F4A1} ' + advice.cause + '\n'
    + '\u{1F527} ' + advice.action + '\n\n'
    + retryLine + '\n'
    + '<b>' + circuitLine + '</b>' + burstLine + '\n\n'
    + '<b>Trace:</b> <code>' + item.traceId + '</code>\n'
    + '<b>Timestamp:</b> ' + formatTimestamp();
}

text = clampTelegramHtml(text);

return [{ json: { ...item, alertText: text } }];

const item = $input.first().json;
const staticData = $getWorkflowStaticData('global');

var now = Date.now();
var retryKey = 'retry_' + item.fingerprint + '_meta';
var retryMeta = staticData[retryKey] || { count: 0, firstSeen: now };

if ((now - retryMeta.firstSeen) > 3600000) {
  retryMeta.count = 0;
  retryMeta.firstSeen = now;
}

var allowedCategory = ['connectivity', 'rate_limit', 'timeout'].includes(item.category);
var isRetryExecution = !!item.retryOf;
var belowLimit = retryMeta.count < 2;
var hasExecutionId = item.executionId && item.executionId !== 'unknown';

var NEVER_RETRY_WORKFLOW_IDS = String($env.NEVER_RETRY_WORKFLOW_IDS || '')
  .split(',')
  .map(function(s) { return s.trim(); })
  .filter(Boolean);
var retryDeniedByWorkflow = NEVER_RETRY_WORKFLOW_IDS.includes(String(item.workflowId));

var shouldRetry = !!item.retryable && allowedCategory && !isRetryExecution && belowLimit && hasExecutionId && !retryDeniedByWorkflow;

var baseDelay = 15;
var exponentialDelay = shouldRetry ? Math.min(baseDelay * Math.pow(2, retryMeta.count), 120) : 0;
var jitter = shouldRetry ? Math.floor(Math.random() * 5) : 0;
var retryDelaySeconds = exponentialDelay + jitter;

if (shouldRetry) {
  retryMeta.count += 1;
  retryMeta.lastRetryAt = now;
  staticData[retryKey] = retryMeta;
}

for (var k of Object.keys(staticData)) {
  if (k.endsWith('_meta') && k.startsWith('retry_')) {
    var meta = staticData[k];
    if (meta && meta.firstSeen && (now - meta.firstSeen) > 3600000) delete staticData[k];
  }
}

if (!shouldRetry) {
  return [];
}

var baseUrl = $env.N8N_BASE_URL || 'http://localhost:5678';
var retryApiUrl = baseUrl + '/api/v1/executions/' + item.executionId + '/retry';

return [{
  json: {
    ...item,
    shouldRetry: true,
    retryAttempt: retryMeta.count,
    retryLimit: 2,
    retryDelaySeconds: retryDelaySeconds,
    retryApiUrl: retryApiUrl,
    autoRetryReason: 'retryable transient failure (attempt ' + retryMeta.count + '/2, delay ' + retryDelaySeconds + 's)'
  }
}];
